// 解析完整 body
const params = new URLSearchParams(rawBody);
const contentStr = decodeURIComponent(params.get('content').replace(/\+/g, ' '));
const content = JSON.parse(contentStr);

// 保存完整解码后的 JSON
const fs = require('fs');
fs.writeFileSync('/Users/yuyun/Documents/openyida-main-2026-03-19/tmp_report_schema.json', JSON.stringify(content, null, 2));

console.log('=== 报表 Schema 顶层信息 ===');
console.log('schemaType:', content.schemaType);
console.log('schemaVersion:', content.schemaVersion);
console.log('pages 数量:', content.pages.length);

const page = content.pages[0];
console.log('\n=== componentsMap (注册组件) ===');
page.componentsMap.forEach((c, i) => {
  console.log(`  ${i+1}. ${c.componentName} (${c.package}@${c.version})`);
});

console.log('\n=== componentsTree 结构 ===');
function printTree(node, depth = 0) {
  const indent = '  '.repeat(depth);
  let info = `${indent}${node.componentName} (id: ${node.id})`;
  if (node.props) {
    if (node.props.fieldId) info += ` [fieldId: ${node.props.fieldId}]`;
    if (node.props.componentTitle && node.props.componentTitle.zh_CN) {
      info += ` [title: ${node.props.componentTitle.zh_CN}]`;
    }
    if (node.props.settings) {
      const s = node.props.settings;
      if (s.labelConfig && s.labelConfig.label && s.labelConfig.label.zh_CN) {
        info += ` [label: ${s.labelConfig.label.zh_CN}]`;
      }
      if (s.titleConfig && s.titleConfig.label && s.titleConfig.label.zh_CN) {
        info += ` [label: ${s.titleConfig.label.zh_CN}]`;
      }
    }
  }
  console.log(info);
  if (node.children) {
    node.children.forEach(c => printTree(c, depth + 1));
  }
}

const tree = page.componentsTree[0];
printTree(tree);

// 提取指标卡的数据集信息
console.log('\n=== 指标卡 (YoushuSimpleIndicatorCard) 数据集详情 ===');
function findComponent(node, name) {
  if (node.componentName === name) return node;
  if (node.children) {
    for (const c of node.children) {
      const found = findComponent(c, name);
      if (found) return found;
    }
  }
  return null;
}

const indicatorCard = findComponent(tree, 'YoushuSimpleIndicatorCard');
if (indicatorCard) {
  const dsm = indicatorCard.props.dataSetModelMap;
  if (dsm && dsm.youshuData) {
    const yd = dsm.youshuData;
    console.log('cubeCode:', yd.dataViewQueryModel.cubeCode);
    console.log('cubeTenantId:', yd.dataViewQueryModel.cubeTenantId);
    
    console.log('\n--- KPI 指标字段 ---');
    if (yd.kpi) {
      yd.kpi.forEach((k, i) => {
        const title = typeof k.title === 'object' ? k.title.zh_CN : k.title;
        console.log(`  ${i+1}. ${title} (fieldCode: ${k.fieldCode}, fieldKey: ${k.fieldKey}, aggregateType: ${k.aggregateType}, dataType: ${k.dataType})`);
      });
    }
    
    console.log('\n--- fieldDefinitionList ---');
    yd.dataViewQueryModel.fieldDefinitionList.forEach((f, i) => {
      const name = typeof f.aliasName === 'object' ? f.aliasName.zh_CN : f.aliasName;
      console.log(`  ${i+1}. ${name} (alias: ${f.alias}, fieldCode: ${f.fieldCode}, dataType: ${f.dataType}, aggregateType: ${f.aggregateType})`);
    });
    
    console.log('\n--- filterList (筛选关联) ---');
    yd.dataViewQueryModel.filterList.forEach((f, i) => {
      console.log(`  ${i+1}. filterKey: ${f.filterKey}`);
      console.log(`     paramId: ${f.paramId}`);
      console.log(`     filterType: ${f.filterType}`);
      console.log(`     conditionType: ${f.conditionType}`);
      console.log(`     alias: ${f.alias}`);
    });
  }
}

// 提取筛选器信息
console.log('\n=== 筛选器详情 ===');
function findAllComponents(node, name, results = []) {
  if (node.componentName === name) results.push(node);
  if (node.children) {
    node.children.forEach(c => findAllComponents(c, name, results));
  }
  return results;
}

const selectFilters = findAllComponents(tree, 'YoushuSelectFilter');
selectFilters.forEach((f, i) => {
  const label = f.props.settings?.labelConfig?.label?.zh_CN || '未知';
  console.log(`\n--- 下拉筛选器 ${i+1}: ${label} ---`);
  console.log(`  fieldId: ${f.props.fieldId}`);
  console.log(`  mode: ${f.props.settings?.mode}`);
  if (f.props.dataSetModelMap?.selectFilter) {
    const sf = f.props.dataSetModelMap.selectFilter;
    console.log(`  cubeCode: ${sf.dataViewQueryModel.cubeCode}`);
    sf.valueField?.forEach(vf => {
      const title = typeof vf.title === 'object' ? vf.title.zh_CN : vf.title;
      console.log(`  valueField: ${title} (fieldCode: ${vf.fieldCode}, dataType: ${vf.dataType})`);
    });
  }
});

